% Recoded by H¸seyin Topan, BEÐ, March 2016
% Functional model is Functional_Model_3.m

function A = Jacobian_XYZ_3_SPOT(unknown, points)

Xs0  = unknown(1);   Xs1 = unknown(2);  Xs2 = unknown(3);
Ys0  = unknown(4);   Ys1 = unknown(5);  Ys2 = unknown(6);   
Zs0  = unknown(7);   Zs1 = unknown(8);  Zs2 = unknown(9);
 
Q0n_0 = unknown(10);  Q0n_1 = unknown(11); Q0n_2 = unknown(12);
Q1n_0 = unknown(13);  Q1n_1 = unknown(14); Q1n_2 = unknown(15);
