A(1, 1) = (tan(psiy)*(2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx)) + 2*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx))) - (conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))^2 - (conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))^2 + (conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))^2 + (conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx))^2)/((2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx)) + 2*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)))*(Xs0 - X + Xs1*dx + Xs2*dx^2) - (2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx)) - 2*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)))*(Ys0 - Y + Ys1*dx + Ys2*dx^2) + (Zs0 - Z + Zs1*dx + Zs2*dx^2)*((conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))^2 - (conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))^2 - (conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))^2 + (conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx))^2)) ;

A(1, 2) = -(tan(psiy)*(2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx)) - 2*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx))) + 2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)) + 2*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx)))/((2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx)) + 2*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)))*(Xs0 - X + Xs1*dx + Xs2*dx^2) - (2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx)) - 2*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)))*(Ys0 - Y + Ys1*dx + Ys2*dx^2) + (Zs0 - Z + Zs1*dx + Zs2*dx^2)*((conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))^2 - (conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))^2 - (conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))^2 + (conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx))^2)) ;

A(1, 3) = (tan(psiy)*((conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))^2 - (conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))^2 - (conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))^2 + (conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx))^2) + 2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx)) - 2*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)))/((2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx)) + 2*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)))*(Xs0 - X + Xs1*dx + Xs2*dx^2) - (2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx)) - 2*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)))*(Ys0 - Y + Ys1*dx + Ys2*dx^2) + (Zs0 - Z + Zs1*dx + Zs2*dx^2)*((conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))^2 - (conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))^2 - (conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))^2 + (conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx))^2)) ;

A(2, 1) = -(tan(psix)*(2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx)) + 2*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx))) - 2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)) + 2*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx)))/((2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx)) + 2*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)))*(Xs0 - X + Xs1*dx + Xs2*dx^2) - (2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx)) - 2*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)))*(Ys0 - Y + Ys1*dx + Ys2*dx^2) + (Zs0 - Z + Zs1*dx + Zs2*dx^2)*((conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))^2 - (conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))^2 - (conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))^2 + (conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx))^2)) ;

A(2, 2) = (tan(psix)*(2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx)) - 2*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx))) - (conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))^2 + (conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))^2 - (conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))^2 + (conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx))^2)/((2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx)) + 2*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)))*(Xs0 - X + Xs1*dx + Xs2*dx^2) - (2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx)) - 2*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)))*(Ys0 - Y + Ys1*dx + Ys2*dx^2) + (Zs0 - Z + Zs1*dx + Zs2*dx^2)*((conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))^2 - (conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))^2 - (conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))^2 + (conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx))^2)) ;

A(2, 3) = -(tan(psix)*((conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))^2 - (conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))^2 - (conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))^2 + (conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx))^2) + 2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx)) + 2*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)))/((2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx)) + 2*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)))*(Xs0 - X + Xs1*dx + Xs2*dx^2) - (2*(conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))*(conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx)) - 2*(conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))*(conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx)))*(Ys0 - Y + Ys1*dx + Ys2*dx^2) + (Zs0 - Z + Zs1*dx + Zs2*dx^2)*((conj(Q0n_0) + conj(Q0n_2)*conj(dx)^2 + conj(Q0n_1)*conj(dx))^2 - (conj(Q1n_0) + conj(Q1n_2)*conj(dx)^2 + conj(Q1n_1)*conj(dx))^2 - (conj(Q2n_0) + conj(Q2n_2)*conj(dx)^2 + conj(Q2n_1)*conj(dx))^2 + (conj(Q3n_0) + conj(Q3n_2)*conj(dx)^2 + conj(Q3n_1)*conj(dx))^2)) ;